# -*- coding: utf-8 -*-
# 202 v2 Scheduler Engine Installer - NeoLegal Production Platform

from pathlib import Path

BASE = Path(r"C:\Users\MSI\Desktop\kik_proje")
PY = BASE / ".py"
PKG = PY / "202"

def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

ENGINE = '# -*- coding: utf-8 -*-\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, SCHEDULER_REGISTRY_FILE\nfrom utils import now_stamp, now_text, ensure_dirs, safe_json, write_json, disk_free_gb\nfrom history import append_history\n\ndef load_jobs():\n    registry = safe_json(SCHEDULER_REGISTRY_FILE)\n    if not registry:\n        return None, []\n    return registry, registry.get("jobs", [])\n\ndef build_execution_plan():\n    registry, jobs = load_jobs()\n    enabled = [j for j in jobs if j.get("enabled") is True]\n\n    # Öncelik düşük sayı = daha önce çalışır\n    enabled.sort(key=lambda j: (int(j.get("priority", 999)), str(j.get("job_id", ""))))\n\n    plan = []\n    for order, job in enumerate(enabled, start=1):\n        plan.append({\n            "order": order,\n            "job_id": job.get("job_id"),\n            "name": job.get("name"),\n            "schedule": job.get("schedule"),\n            "action": job.get("action"),\n            "command": job.get("command"),\n            "priority": job.get("priority"),\n            "status": "PLANNED",\n        })\n\n    return registry, jobs, plan\n\ndef validate_plan(registry, jobs, plan):\n    errors = []\n    warnings = []\n\n    if registry is None:\n        errors.append("Scheduler registry okunamadı.")\n\n    if not jobs:\n        errors.append("Scheduler job listesi boş.")\n\n    if not plan:\n        warnings.append("Enabled job yok; plan boş.")\n\n    seen = set()\n    for item in plan:\n        jid = item.get("job_id")\n        if jid in seen:\n            errors.append(f"Duplicate planned job: {jid}")\n        seen.add(jid)\n\n        if not item.get("command"):\n            warnings.append(f"{jid}: command boş.")\n\n        if item.get("status") != "PLANNED":\n            warnings.append(f"{jid}: beklenmeyen plan status: {item.get(\'status\')}")\n\n    score = 100 - min(60, len(errors) * 15) - min(30, len(warnings) * 3)\n    score = max(0, score)\n\n    decision = "SCHEDULER ENGINE BLOCKED" if errors else ("SCHEDULER ENGINE REVIEW" if warnings else "SCHEDULER ENGINE READY")\n\n    return {\n        "score": score,\n        "decision": decision,\n        "errors": errors,\n        "warnings": warnings,\n    }\n\ndef run(record_history=True):\n    ensure_dirs(STATE_DIR, REPORT_DIR)\n    ts = now_stamp()\n    registry, jobs, plan = build_execution_plan()\n    result = validate_plan(registry, jobs, plan)\n\n    payload = {\n        "module": "202 v2 Scheduler Engine",\n        "created_at": now_text(),\n        "disk_free_gb": disk_free_gb(BASE_DIR),\n        "registry_file": str(SCHEDULER_REGISTRY_FILE),\n        "total_jobs": len(jobs),\n        "planned_jobs": len(plan),\n        "plan": plan,\n        "result": result,\n    }\n\n    state = STATE_DIR / f"202_v2_scheduler_engine_state_{ts}.json"\n    report = REPORT_DIR / f"202_v2_scheduler_engine_raporu_{ts}.txt"\n    write_json(state, payload)\n\n    lines = [\n        "=" * 80,\n        "202 v2 SCHEDULER ENGINE",\n        "=" * 80,\n        f"Score        : {result[\'score\']} / 100",\n        f"Decision     : {result[\'decision\']}",\n        f"Total Jobs   : {len(jobs)}",\n        f"Planned Jobs : {len(plan)}",\n        "",\n        "EXECUTION PLAN",\n        "-" * 80,\n    ]\n\n    for item in plan:\n        lines.append(\n            f"{item[\'order\']:02d}. {item.get(\'job_id\'):<24} | "\n            f"priority={item.get(\'priority\')} | {item.get(\'action\')} | {item.get(\'schedule\')}"\n        )\n\n    lines += [\n        "",\n        "ERRORS",\n        "-" * 80,\n    ]\n    if result["errors"]:\n        for e in result["errors"]:\n            lines.append(f"- {e}")\n    else:\n        lines.append("Errors: 0")\n\n    lines += [\n        "",\n        "WARNINGS",\n        "-" * 80,\n    ]\n    if result["warnings"]:\n        for w in result["warnings"]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("Warnings: 0")\n\n    lines += [\n        "",\n        "NOT:",\n        "202 v2 görevleri çalıştırmaz; execution plan oluşturur.",\n        "",\n        "Dosyalar:",\n        str(state),\n        str(report),\n    ]\n\n    report.write_text("\\n".join(lines), encoding="utf-8")\n\n    if record_history:\n        append_history({\n            "event": "SchedulerExecutionPlanCreated",\n            "status": "PASS" if not result["errors"] else "FAIL",\n            "decision": result["decision"],\n            "score": result["score"],\n            "total_jobs": len(jobs),\n            "planned_jobs": len(plan),\n            "state_file": str(state),\n            "report_file": str(report),\n        })\n\n    return {\n        "payload": payload,\n        "result": result,\n        "paths": {"state": str(state), "report": str(report)},\n    }\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom registry import run as run_registry\nfrom history import run as run_history\nfrom scheduler import record_plan\nfrom engine import run as run_engine\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--init", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    parser.add_argument("--plan", action="store_true")\n    parser.add_argument("--engine", action="store_true")\n    parser.add_argument("--history", action="store_true")\n    args = parser.parse_args()\n\n    if args.history:\n        h = run_history()\n        print("="*80)\n        print("202 PACKAGE HISTORY TAMAMLANDI")\n        print("="*80)\n        print(f"Decision : {h[\'result\'][\'decision\']} ({h[\'result\'][\'score\']}/100)")\n        print(h["paths"]["report"])\n        return\n\n    if args.engine:\n        e = run_engine(record_history=True)\n        print("="*80)\n        print("202 v2 SCHEDULER ENGINE TAMAMLANDI")\n        print("="*80)\n        print(f"Decision     : {e[\'result\'][\'decision\']} ({e[\'result\'][\'score\']}/100)")\n        print(f"Total Jobs   : {e[\'payload\'][\'total_jobs\']}")\n        print(f"Planned Jobs : {e[\'payload\'][\'planned_jobs\']}")\n        print("")\n        print("Dosyalar:")\n        print(e["paths"]["report"])\n        return\n\n    if args.plan:\n        p = record_plan()\n        print("="*80)\n        print("202 PACKAGE SCHEDULER PLAN TAMAMLANDI")\n        print("="*80)\n        print(f"Decision     : {p[\'result\'][\'decision\']} ({p[\'result\'][\'score\']}/100)")\n        print(f"Total Jobs   : {len(p[\'jobs\'])}")\n        print(f"Enabled Jobs : {len(p[\'enabled_jobs\'])}")\n        return\n\n    r = run_registry(init=args.init)\n    print("="*80)\n    print("202 PACKAGE SCHEDULER TAMAMLANDI")\n    print("="*80)\n    print(f"Decision : {r[\'result\'][\'decision\']} ({r[\'result\'][\'score\']}/100)")\n    print(f"Jobs     : {len(r[\'registry\'].get(\'jobs\', []))}")\n    print("")\n    print("Dosyalar:")\n    print(r["paths"]["registry"])\n    print(r["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

def main():
    if not PKG.exists():
        raise SystemExit(r"202 paketi bulunamadı. Önce 202_Package_Installer.py çalıştırılmalı.")

    write("engine.py", ENGINE)
    write("manager.py", MANAGER)

    print("="*80)
    print("202 v2 SCHEDULER ENGINE INSTALLER TAMAMLANDI")
    print("="*80)
    print("Güncellenen / eklenen dosyalar:")
    print(PKG / "engine.py")
    print(PKG / "manager.py")
    print("")
    print("Şimdi çalıştır:")
    print(r'cd /d C:\Users\MSI\Desktop\kik_proje')
    print(r'python ".py\202_Platform_Scheduler.py" --engine')

if __name__ == "__main__":
    main()
